To achieve one index cache per index file, you can use a separate cache for each index file. Here's an example of how you can implement this in Python using the `functools` and `lru_cache` decorators:

```python
from functools import wraps
from typing import Callable, Any

def index_cache(index_file):
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Create a cache for the current index file
            cache = {}
            def cached_func(*args, **kwargs):
                # Check if the result is already in the cache
                if args in cache:
                    return cache[args]
                else:
                    # If not, calculate the result and store it in the cache
                    result = func(*args, **kwargs)
                    cache[args] = result
                    return result
            return cached_func
        return wrapper
    return decorator

